void distillation_reflux_controller(float R,unsigned long period,int rv,int dv){
  unsigned long t_reflux=(unsigned long)(R*period);
  unsigned long t_dist=period-t_reflux;
  digitalWrite(rv,HIGH);digitalWrite(dv,LOW);delay(t_reflux);
  digitalWrite(rv,LOW);digitalWrite(dv,HIGH);delay(t_dist);
  digitalWrite(dv,LOW);
}
